
import { createWebHistory, createRouter } from 'vue-router';
import Main from "../components/BlueMain"
import HMmain from "../components/Human/HMmain"
import pfMain from "../components/Human/pfViewMain.vue"


const routes = [
        {path:"/",name:"home",component:Main},
        {path:"/H",name:"HMhome",component:HMmain},
        {path:"/H/:id",name:"pfMain",component:pfMain},
]

export const router = createRouter({
    history: createWebHistory(),
    routes,
});